20			</svg>
21		);
22	}
23	
24	function DownloadIcon() {
25		return (
26			<svg
27				aria-hidden="true"
28				width={14}
29				height={14}
30				viewBox="0 0 24 24"
31				fill="none"
32				stroke="currentColor"
33				strokeWidth={1.5}
34				strokeLinecap="round"
35				strokeLinejoin="round"
36			>
37				<path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
38				<path d="M7 10l5 5 5-5" />
39				<path d="M12 15V3" />
40			</svg>
41		);
42	}
43	
44	function Spinner() {
45		return (
46			<svg
47				aria-hidden="true"
48				width={14}
49				height={14}
50				viewBox="0 0 24 24"
51				fill="none"
52				stroke="currentColor"
53				strokeWidth={2}
54				strokeLinecap="round"
55				className="animate-spin"
56			>
57				<path d="M21 12a9 9 0 1 1-6.22-8.56" />
58			</svg>
59		);
60	}
61	
62	export function VoiceoverButton({
63		jobId,
64		disabled,
65	}: {
66		jobId: string;
67		disabled?: boolean;
68	}) {
69		const [audioUrl, setAudioUrl] = useState<string | null>(null);
70		const [pending, setPending] = useState(false);
71		const [error, setError] = useState<string | null>(null);
72	
73		async function generate() {
74			setError(null);
75			setPending(true);
76			try {
77				const response = await fetch(
78					`${env.NEXT_PUBLIC_SERVER_URL}/api/v1/video-jobs/${jobId}/voiceover`,
79					{ method: "POST" },
80				);
81				if (!response.ok) {
82					const text = await response.text().catch(() => "");
83					throw new Error(text || `Server returned ${response.status}`);
84				}
85				const data = (await response.json()) as { audioUrl?: string };
86				if (!data.audioUrl) {
87					throw new Error("Server did not return audioUrl");
88				}
89				setAudioUrl(`${env.NEXT_PUBLIC_SERVER_URL}${data.audioUrl}`);
90			} catch (e) {
91				setError(e instanceof Error ? e.message : "Voiceover failed");
92			} finally {
93				setPending(false);
94			}
95		}
96	
97		if (audioUrl) {
98			return (
99				<div className="flex flex-col gap-3">
100					<div className="mono text-[11px] text-[var(--color-magenta)] uppercase tracking-[0.08em]">
101						Powered by Gradium
102					</div>
103					{/* biome-ignore lint/a11y/useMediaCaption: hackathon demo, no captions */}
104					<audio
105						data-testid="result-audio"
106						controls
107						autoPlay
108						src={audioUrl}
109						className="w-full"
110					/>
111					<div className="flex items-center gap-3">
112						<a
113							href={audioUrl}
114							download={`cf-${jobId}-voiceover.wav`}
115							className="inline-flex h-9 items-center gap-2 rounded-md border border-[var(--color-border)] bg-transparent px-3 font-medium text-[12px] text-[var(--color-text)] transition-[background-color,border-color] duration-[120ms] hover:border-[var(--color-border-strong)] hover:bg-[var(--color-elev-1)]"
116						>
117							<DownloadIcon />
118							Download voiceover
119						</a>
120						<button
121							type="button"
122							onClick={() => {
123								setAudioUrl(null);
124								void generate();
